import React, { useState, useEffect } from 'react';

const TableComponent = () => {
    const [records, setRecords] = useState([
        { id: 1, name: 'adam', age: 25 },
        { id: 2, name: 'james', age: 30 },
        { id: 3, name: 'nick', age: 28 },
        { id: 4, name: 'john', age: 29 }
    ]);
    const [filter, setFilter] = useState('');
    const [sortField, setSortField] = useState('name');
    const [sortOrder, setSortOrder] = useState('asc');

    // Function to apply filter
    const applyFilter = () => {
        const filtered = records.filter(record => 
            record.name.toLowerCase().includes(filter.toLowerCase())
        );
        setRecords(filtered);
    };

    // Function to sort records
    const sortRecords = () => {
        const sorted = [...records];
        if (sortOrder === 'asc') {
            sorted.sort((a, b) => a[sortField].toLowerCase().localeCompare(b[sortField].toLowerCase()));
        } else {
            sorted.sort((a, b) => b[sortField].toLowerCase().localeCompare(a[sortField].toLowerCase()));
        }
        setRecords(sorted);
    };

    // Effect to handle sorting and filtering on state changes
    useEffect(() => {
        applyFilter();
        sortRecords();
    }, [filter, sortField, sortOrder]);

    return (
        <div>
            <input
                type="text"
                placeholder="Filter by name..."
                value={filter}
                onChange={(e) => setFilter(e.target.value)}
                className="filter-input"
            />
            <button
                onClick={() => setSortField('name')}
                className="sort-button"
            >
                Sort by name
            </button>
            <button
                onClick={() => setSortOrder(sortOrder === 'asc' ? 'desc' : 'asc')}
                className="sort-button"
            >
                Sort order
            </button>
            <table className="table">
                <thead>
                    <tr>
                        <th onClick={() => setSortField('id')}>id</th>
                        <th onClick={() => setSortField('name')}>name</th>
                        <th onClick={() => setSortField('age')}>age</th>
                    </tr>
                </thead>
